class Solution:
    def minimumSum(self, nums):
        n = len(nums)
        best = -1
        for i in range(n):
            for j in range(i + 1, n):
                for k in range(j + 1, n):
                    if nums[i] < nums[j] and nums[k] < nums[j]:
                        total = nums[i] + nums[j] + nums[k]
                        if best == -1 or total < best:
                            best = total
        return best

