class Solution:
    def minimumSum(self, nums):
        n = len(nums)
        INF = float('inf')
        left_min = [INF] * n
        running = INF
        for i in range(n):
            left_min[i] = running
            running = min(running, nums[i])
        right_min = [INF] * n
        running = INF
        for i in range(n - 1, -1, -1):
            right_min[i] = running
            running = min(running, nums[i])
        best = -1
        for j in range(1, n - 1):
            if left_min[j] < nums[j] and right_min[j] < nums[j]:
                total = left_min[j] + nums[j] + right_min[j]
                if best == -1 or total < best:
                    best = total
        return best

