var minimumSum = function(nums) {
    const n = nums.length;
    const INF = Infinity;
    const leftMin = new Array(n).fill(INF);
    let running = INF;
    for (let i = 0; i < n; i++) {
        leftMin[i] = running;
        running = Math.min(running, nums[i]);
    }
    const rightMin = new Array(n).fill(INF);
    running = INF;
    for (let i = n - 1; i >= 0; i--) {
        rightMin[i] = running;
        running = Math.min(running, nums[i]);
    }
    let best = -1;
    for (let j = 1; j < n - 1; j++) {
        if (leftMin[j] < nums[j] && rightMin[j] < nums[j]) {
            const total = leftMin[j] + nums[j] + rightMin[j];
            if (best === -1 || total < best) best = total;
        }
    }
    return best;
};
